// Parse incoming support request
const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    conversation_id: body.conversation_id,
    client_id: body.client_id,
    customer_name: body.customer_name || 'Customer',
    content: body.content,
    urgency: body.urgency || 'normal',
    category: body.category || 'general'
  }
}];

// Auto-draft response based on category
const data = $input.first().json;
let draft = '';

const templates = {
  'billing': `Hi ${data.customer_name},

Thanks for reaching out about your billing inquiry. I've reviewed your account and here's what I found:

[Draft response - review before sending]

If you have any other questions, just reply here.
— SAOS Support`,
  'technical': `Hi ${data.customer_name},

I received your technical support request. Let me look into this for you:

[Investigating - draft response pending agent review]

I'll update you shortly with next steps.
— SAOS Support`,
  'general': `Hi ${data.customer_name},

Thank you for contacting SAOS support. I've received your message about:

"${data.content.substring(0, 200)}${data.content.length > 200 ? '...' : ''}"

[Draft response queued for human review]

We'll get back to you shortly.
— SAOS Support`
};

draft = templates[data.category] || templates['general'];

return [{
  json: {
    ...data,
    draft_response: draft,
    status: 'drafted',
    requires_review: true
  }
}];
